import{_ as o,c as t,o as i,a1 as n}from"./chunks/framework.DDNAyvCW.js";const p=JSON.parse('{"title":"AI Settings","description":"","frontmatter":{},"headers":[],"relativePath":"docs/ai/settings/index.md","filePath":"docs/ai/settings/index.md"}'),a={name:"docs/ai/settings/index.md"};function r(s,e,l,d,c,u){return i(),t("div",null,e[0]||(e[0]=[n('<h1 id="ai-settings" tabindex="-1">AI Settings <a class="header-anchor" href="#ai-settings" aria-label="Permalink to &quot;AI Settings&quot;">​</a></h1><p>Configure AI providers, models, and interaction modes to customize your AI experience.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before configuring AI settings, make sure you have:</p><ul><li>A Chaterm installation (version with AI support)</li><li>Use the built-in model or an API key or credentials for at least one model provider (see <a href="/docs/ai/llms/">Model Configuration</a> for supported providers)</li><li>Network access to your chosen provider&#39;s API endpoint (or a local Ollama instance)</li></ul><hr><h2 id="creating-a-new-ai-dialog" tabindex="-1">Creating a New AI Dialog <a class="header-anchor" href="#creating-a-new-ai-dialog" aria-label="Permalink to &quot;Creating a New AI Dialog&quot;">​</a></h2><p>Each AI dialog is an independent session with its own mode, model, and context. You can run multiple dialogs simultaneously.</p><ol><li>Click <strong>&quot;AI&quot;</strong> in the left menu to open the AI dialog panel.</li><li>Click the <strong>&quot;New Chat&quot;</strong> button at the top of the panel.</li><li>Choose an <strong>interaction mode</strong>: <ul><li><strong>Command</strong> — AI generates commands for the active terminal</li><li><strong>Agent</strong> — AI autonomously executes multi-step tasks</li></ul></li><li>Select a <strong>model</strong> from the dropdown list. Only models you have configured will appear.</li><li><em>(Agent mode only)</em> Type <code>@</code> in the input box to select one or more <strong>target hosts</strong>.</li><li>Type your message and press <strong>Enter</strong> to begin.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can have multiple dialogs open at once, each using a different mode or model. This is useful for comparing model responses or working on parallel tasks.</p></div><p>For a detailed explanation of each mode, see <a href="/docs/ai/dialogs/">AI Dialogs</a>.</p><hr><h2 id="configuring-a-model-provider" tabindex="-1">Configuring a Model Provider <a class="header-anchor" href="#configuring-a-model-provider" aria-label="Permalink to &quot;Configuring a Model Provider&quot;">​</a></h2><p>To use AI features, you need at least one configured model provider.</p><ol><li>Open <strong>Settings</strong> by clicking the gear icon in the top-right corner.</li><li>Navigate to the <strong>&quot;Models&quot;</strong> tab in the left menu.</li><li>Click <strong>&quot;Add Model&quot;</strong>.</li><li>Select an <strong>API provider</strong> from the list: <ul><li><strong>LiteLLM</strong> — Unified interface supporting multiple providers</li><li><strong>OpenAI</strong> — OpenAI-compatible API</li><li><strong>Bedrock</strong> — Amazon Bedrock (enterprise)</li><li><strong>Anthropic</strong> — Anthropic API</li><li><strong>DeepSeek</strong> — DeepSeek API</li><li><strong>Ollama</strong> — Locally deployed models</li></ul></li><li>Fill in the required <strong>authentication fields</strong> for your chosen provider (API key, endpoint URL, region, etc.).</li><li>Enter or select a <strong>model name</strong>.</li><li>Click <strong>&quot;Test Connection&quot;</strong> to verify the configuration.</li><li>If the test succeeds, click <strong>&quot;Save&quot;</strong>.</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Keep your API keys secure. If you suspect a key has been compromised, rotate it immediately with your provider and update the configuration in Chaterm.</p></div><p>For provider-specific field reference tables and detailed setup instructions, see <a href="/docs/ai/llms/">Model Configuration</a>.</p><hr><h2 id="exporting-a-chat" tabindex="-1">Exporting a Chat <a class="header-anchor" href="#exporting-a-chat" aria-label="Permalink to &quot;Exporting a Chat&quot;">​</a></h2><p>You can export any conversation for sharing or archival.</p><ol><li>Open the conversation you want to export.</li><li>Click the <strong>export</strong> button (typically in the top-right area of the dialog panel).</li><li>Choose the export format and save location.</li></ol><p>Exported chats preserve the full conversation including AI responses, commands, and execution output.</p><hr><h2 id="related-documentation" tabindex="-1">Related Documentation <a class="header-anchor" href="#related-documentation" aria-label="Permalink to &quot;Related Documentation&quot;">​</a></h2><ul><li><a href="/docs/ai/dialogs/">AI Dialogs</a> — Understand Chat, Command, and Agent modes in depth</li><li><a href="/docs/ai/llms/">Model Configuration</a> — Provider-specific setup guides and field references</li><li><a href="/docs/ai/preferences/">AI Preferences</a> — Configure reasoning depth, auto-execution, security, and proxy settings</li></ul>',25)]))}const h=o(a,[["render",r]]);export{p as __pageData,h as default};
